    const n = points.length;
    const yMap = new Map<number, number[]>();

    // Group points by their y-coordinate
    for (const [x, y] of points) {
        if (!yMap.has(y)) {
            yMap.set(y, []);
        }
        yMap.get(y)!.push(x);
    }

    let result = 0;

    // For each y-coordinate, process the x-coordinates
    for (const [y, xs] of yMap.entries()) {
        const m = xs.length;
        if (m < 2) continue;

        // Sort x-coordinates for easier processing
        xs.sort((a, b) => a - b);

        // For each pair of x-coordinates in the same y-level, count how many pairs they form
